  const elementId = argv[argv.indexOf('--element-id') + 1];
  if (!elementId) { console.error('element-set-phase requires --element-id <id>'); process.exit(1); }
  const payload = { type: 'setElementPhase', elementId };
  const pcIdx = argv.indexOf('--phase-created-id');
  if (pcIdx !== -1) payload.phaseCreatedId = argv[pcIdx + 1];
  const pdIdx = argv.indexOf('--phase-demolished-id');
  if (pdIdx !== -1) payload.phaseDemolishedId = argv[pdIdx + 1];
  if (argv.includes('--clear-demolished')) payload.clearDemolished = true;
  await postCommand(modelId, userId, payload);
  return;
}

if (cmd === 'view-set-phase') {
  if (!modelId) usage();
  const viewId = argv[argv.indexOf('--view-id') + 1];
  const phaseId = argv[argv.indexOf('--phase-id') + 1];
  if (!viewId || !phaseId) { console.error('view-set-phase requires --view-id <id> --phase-id <id>'); process.exit(1); }
  await postCommand(modelId, userId, { type: 'setViewPhase', viewId, phaseId });
  return;
}

if (cmd === 'view-set-phase-filter') {
  if (!modelId) usage();
  const viewId = argv[argv.indexOf('--view-id') + 1];
  const phaseFilter = argv[argv.indexOf('--phase-filter') + 1];
  if (!viewId || !phaseFilter) { console.error('view-set-phase-filter requires --view-id <id> --phase-filter <filter>'); process.exit(1); }
  await postCommand(modelId, userId, { type: 'setViewPhaseFilter', viewId, phaseFilter });
  return;
}

if (cmd === 'create-toposolid') {
  if (!modelId) usage();
  const toposolidId = argv[argv.indexOf('--id') + 1];
  const boundaryStr = argv[argv.indexOf('--boundary') + 1];
  if (!toposolidId || !boundaryStr) {
    console.error('create-toposolid requires --id <id> --boundary <json>');
    process.exit(1);
  }
  const payload = { type: 'CreateToposolid', toposolidId, boundaryMm: JSON.parse(boundaryStr) };
  const samplesIdx = argv.indexOf('--height-samples');
  if (samplesIdx !== -1) payload.heightSamples = JSON.parse(argv[samplesIdx + 1]);
  const gridIdx = argv.indexOf('--heightmap-grid');
  if (gridIdx !== -1) payload.heightmapGridMm = JSON.parse(argv[gridIdx + 1]);
  const thickIdx = argv.indexOf('--thickness-mm');
  if (thickIdx !== -1) payload.thicknessMm = Number(argv[thickIdx + 1]);
  const baseIdx = argv.indexOf('--base-elevation-mm');
  if (baseIdx !== -1) payload.baseElevationMm = Number(argv[baseIdx + 1]);
  const nameIdx = argv.indexOf('--name');
  if (nameIdx !== -1) payload.name = argv[nameIdx + 1];
  await postCommand(modelId, userId, payload);
  return;
}

if (cmd === 'update-toposolid') {
  if (!modelId) usage();
  const toposolidId = argv[argv.indexOf('--id') + 1];
  if (!toposolidId) { console.error('update-toposolid requires --id <id>'); process.exit(1); }
  const payload = { type: 'UpdateToposolid', toposolidId };
  const thickIdx = argv.indexOf('--thickness-mm');
  if (thickIdx !== -1) payload.thicknessMm = Number(argv[thickIdx + 1]);
  const baseIdx = argv.indexOf('--base-elevation-mm');
  if (baseIdx !== -1) payload.baseElevationMm = Number(argv[baseIdx + 1]);
  const nameIdx = argv.indexOf('--name');
  if (nameIdx !== -1) payload.name = argv[nameIdx + 1];
  if (argv.includes('--pinned')) payload.pinned = true;
  await postCommand(modelId, userId, payload);
  return;
}

if (cmd === 'delete-toposolid') {
  if (!modelId) usage();
  const toposolidId = argv[argv.indexOf('--id') + 1];
  if (!toposolidId) { console.error('delete-toposolid requires --id <id>'); process.exit(1); }
  await postCommand(modelId, userId, { type: 'DeleteToposolid', toposolidId });
  return;
}

